  'settings.themeItem2': { zh: '品牌色：商务蓝、石墨灰、灵感紫、翡翠绿、曜石红。', en: 'Brand color: Business Blue, Graphite Gray, Inspiration Purple, Jade Green, Obsidian Red.' },
  'settings.themeItem3': { zh: '切换品牌色会影响按钮、导航高亮和强调色。', en: 'Switching brand color affects buttons, navigation highlights, and accent colors.' },
  'settings.gitBranch': { zh: '显示当前分支', en: 'Show Current Branch' },
