  'settings.gitBranchItem1': { zh: '开关"显示当前分支"后，群聊输入框上方会显示工作目录的 Git 分支。', en: 'Toggle "Show Current Branch" to display the Git branch of the work directory above the chat input.' },
  'settings.gitBranchItem2': { zh: '可在该处直接查看并切换工作目录所在分支。', en: 'You can view and switch branches directly from there.' },
