  'chatrooms.groupSettings': { zh: '群设置', en: 'Group Settings' },
  'chatrooms.groupSettingsDesc': { zh: '点击群标题、头像或右上角设置按钮打开"群设置"，可管理：群组名称、头像、群组描述、工作目录、默认接收助手、助手触发模式、群规则、外部平台机器人绑定、清空消息、删除对话。', en: 'Click the group title, avatar, or settings button in the top right to open "Group Settings" to manage: group name, avatar, description, work directory, default receiving agent, agent trigger mode, group rules, external platform bot binding, clear messages, delete conversation.' },
  'chatrooms.workDir': { zh: '工作目录', en: 'Work Directory' },
  'chatrooms.workDirEyebrow': { zh: 'Work dir', en: 'Work dir' },
  'chatrooms.workDirItem1': { zh: '工作目录决定助手执行文件操作和命令时的基础位置。', en: 'Work directory determines the base location for agents to perform file operations and execute commands.' },
  'chatrooms.workDirItem2': { zh: '设置了群工作目录后，群内助手共享该目录。', en: 'After setting a group work directory, all agents in the group share that directory.' },
  'chatrooms.workDirItem3': { zh: '桌面端可以选择目录、打开目录、复制路径，或用指定终端打开。', en: 'On desktop, you can select directory, open directory, copy path, or open with a specified terminal.' },
  'chatrooms.workDirItem4': { zh: '留空时使用默认目录：~/.teamagentx/workspace/<群聊ID>。', en: 'When left empty, uses default directory: ~/.teamagentx/workspace/<ChatroomID>.' },
  'chatrooms.groupRules': { zh: '群规则', en: 'Group Rules' },
  'chatrooms.groupRulesEyebrow': { zh: 'Room rules', en: 'Room rules' },
  'chatrooms.groupRulesNote': { zh: '群规则会注入到群内所有助手上下文中。适合写：', en: 'Group rules are injected into all agents\' context in the group. Suitable for:' },
  'chatrooms.groupRulesExample': { zh: `- 所有回复使用中文。
- 修改代码前先说明计划。
- 不确定的信息需要明确说明。
- 输出方案时同时给出风险。`, en: `- All responses in Chinese.
- Explain plan before modifying code.
- Clearly state uncertain information.
- Provide risks when outputting solutions.` },
  'chatrooms.memberManage': { zh: '成员管理', en: 'Member Management' },
  'chatrooms.memberManageEyebrow': { zh: 'Members', en: 'Members' },
  'chatrooms.memberManageItem1': { zh: '成员分组显示：群主、普通助手、系统助手。', en: 'Members are grouped: Group owner, Regular agents, System agents.' },
  'chatrooms.memberManageItem2': { zh: '点击助手查看详情；点击 @ 按钮或右键把助手插入输入框。', en: 'Click an agent to view details; click @ button or right-click to insert agent into input box.' },
  'chatrooms.memberManageItem3': { zh: '可移除群主、非系统助手；可添加当前不在群内的活跃助手。', en: 'Can remove non-owner, non-system agents; can add active agents not currently in the group.' },
  'chatrooms.memberManageItem4': { zh: '快速对话群聊不允许添加新助手。', en: 'Quick chat rooms do not allow adding new agents.' },
  'chatrooms.taskExecution': { zh: '任务执行过程', en: 'Task Execution Process' },
  'chatrooms.taskExecutionEyebrow': { zh: 'Execution', en: 'Execution' },
  'chatrooms.taskExecutionItem1': { zh: '流式输出：实时查看思考、工具调用和输出。', en: 'Streaming output: View thinking, tool calls, and output in real-time.' },
  'chatrooms.taskExecutionItem2': { zh: '任务队列：查看某个助手排队中的任务。', en: 'Task queue: View queued tasks for a specific agent.' },
  'chatrooms.taskExecutionItem3': { zh: '任务看板：查看群内所有助手当前任务状态。', en: 'Task board: View current task status for all agents in the group.' },
  'chatrooms.taskExecutionItem4': { zh: '执行详情：查看历史执行事件、耗时、Token 和工具结果。', en: 'Execution details: View historical execution events, duration, tokens, and tool results.' },
  'chatrooms.taskExecutionItem5': { zh: '查看上下文：查看助手最近上下文、系统提示词和工具调用信息。', en: 'View context: View agent\'s recent context, system prompts, and tool call information.' },
  'chatrooms.taskExecutionItem6': { zh: '历史执行结果：查看某个助手在当前群聊里的历史记录。', en: 'Historical execution results: View historical records of an agent in the current chatroom.' },
  'chatrooms.taskExecutionNote': { zh: '任务执行时，顶部会显示"停止所有任务"按钮，也可以在流式面板中停止单个助手。', en: 'During task execution, a "Stop All Tasks" button appears at the top; you can also stop individual agents in the streaming panel.' },
  'chatrooms.moreFeaturesTitle': { zh: '更多功能与消息操作', en: 'More Features & Message Operations' },
  'chatrooms.moreFeaturesDesc': { zh: '群聊右上角"更多"菜单包含：群规则、截图聊天记录、定时任务、历史记录、清空消息。若群工作目录中存在 package.json，顶部还会显示脚本菜单。消息支持回复、跳转助手详情、查看执行详情、归档历史、删除或批量选择；收到未读消息时左侧会显示未读数量，进入群聊后自动标记已读。', en: 'The "More" menu in the top right of the chatroom includes: group rules, screenshot chat history, scheduled tasks, history, clear messages. If package.json exists in the group work directory, a script menu also appears at the top. Messages support reply, jump to agent details, view execution details, archive to history, delete, or batch select; unread count appears on the left when there are unread messages, and automatically marks as read when entering the chatroom.' },

